const mkI = (en, lt, amount, unit) => ({
  en,
  lt,
  amount,
  unit
});
const SLOTS = ["breakfast", "lunch", "snack", "dinner"];
const getMeal = (v, slot, person) => {
  if (!v) return null;
  const s = v.meals[slot];
  if (!s) return null;
  if (s.both) return s.both;
  return s[person] || null;
};

// Resolve which person key to use for eaten/notes storage
const personKey = (v, slot) => {
  if (!v) return "both";
  const s = v.meals[slot];
  if (!s || s.both) return "both";
  return null; // caller handles R / I separately
};
const fmtNum = n => {
  const r = Math.round(n * 10) / 10;
  return Number.isInteger(r) ? String(r) : r.toFixed(1);
};

