import { useState, useRef, useEffect, useCallback } from "react";
import { supabase } from "./supabase";

// ─── Fonts ────────────────────────────────────────────────────────────────────
const FONT = `@import url('https://fonts.googleapis.com/css2?family=Fraunces:ital,wght@0,300;0,500;0,700;1,400&family=DM+Sans:wght@300;400;500;600&family=Caveat:wght@500;700&display=swap');`;

// ─── i18n ─────────────────────────────────────────────────────────────────────
const T = {
  en: {
    title:"Our Meal Plan", subtitle:"low-FODMAP · gluten-free",
    plan:"Plan", shopping:"Shopping", tips:"Tips",
    selectVariant:"Choose variant", changeVariant:"Change", removeVariant:"Remove variant",
