    kcal:"kcal", protein:"Protein", carbs:"Carbs", fat:"Fat",
    dailyTotal:"Day total", eaten:"eaten",
    viewRecipe:"View recipe",
    notePlaceholder:"Was it good? Any issues preparing it?",
