  lt: {
    title:"Mūsų Mitybos Planas", subtitle:"mažai FODMAP · be glitimo",
    plan:"Planas", shopping:"Apsipirkimas", tips:"Patarimai",
    selectVariant:"Pasirinkti variantą", changeVariant:"Keisti", removeVariant:"Pašalinti variantą",
